Queue implementation using an array in Python:

python
class Queue:
    def __init__(self, max_size):
        self.max_size = max_size
        self.queue = [None] * max_size
        self.size = 0

    def enqueue(self, item):
        if self.size < self.max_size:
            self.queue[self.size] = item
            self.size += 1
        else:
            print('Queue is full')

    def dequeue(self):
        if self.size > 0:
            item = self.queue[0]
            self.queue[0] = None
            for i in range(1, self.size):
                self.queue[i-1] = self.queue[i]
            self.size -= 1
            return item
        else:
            print('Queue is empty')

    def peek(self):
        if self.size > 0:
            return self.queue[0]
        else:
            print('Queue is empty')

    def is_empty(self):
        return self.size == 0

q = Queue(5)
q.enqueue(1)
q.enqueue(2)
q.enqueue(3)
print(q.peek())  # Output: 1
q.dequeue()
print(q.peek())  # Output: 2
print(q.is_empty())  # Output: False

Time complexity of each operation:
- Enqueue: O(1)
- Dequeue: O(n) in the worst case
- Peek: O(1)
- is_empty: O(1)

Linked list implementation in Python:

python
class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def insert(self, data):
        if not self.head:
            self.head = Node(data)
        else:
            current = self.head
            while current.next:
                current = current.next
            current.next = Node(data)

    def delete(self, data):
        if self.head is None:
            return
        if self.head.data == data:
            self.head = self.head.next
            return
        current = self.head
        while current.next:
            if current.next.data == data:
                current.next = current.next.next
                return
            current = current.next

    def search(self, data):
        current = self.head
        while current:
            if current.data == data:
                return True
            current = current.next
        return False

    def display(self):
        elements = []
        current_node = self.head
        while current_node:
            elements.append(current_node.data)
            current_node = current_node.next
        return elements

ll = LinkedList()
ll.insert('A')
ll.insert('B')
ll.insert('C')
print(ll.display())  # Output: ['A', 'B', 'C']
ll.delete('B')
print(ll.display())  # Output: ['A', 'C']
print(ll.search('A'))  # Output: True
